import threading
from typing import Callable, Dict, List, Any

class Singleton(type):
    """
    A thread-safe implementation of Singleton as a metaclass.
    """
    _instances = {}
    _lock: threading.Lock = threading.Lock()

    def __call__(cls, *args, **kwargs):
        with cls._lock:
            if cls not in cls._instances:
                instance = super().__call__(*args, **kwargs)
                cls._instances[cls] = instance
        return cls._instances[cls]

class AppConfig(metaclass=Singleton):
    def __init__(self):
        self._config: Dict[str, Any] = {}

    def get(self, key: str) -> Any:
        return self._config.get(key)

    def set(self, key: str, value: Any) -> None:
        self._config[key] = value

class EventEmitter:
    def __init__(self):
        self._subscribers: Dict[str, List[Callable]] = {}

    def subscribe(self, event: str, callback: Callable) -> None:
        if event not in self._subscribers:
            self._subscribers[event] = []
        self._subscribers[event].append(callback)

    def unsubscribe(self, event: str, callback: Callable) -> None:
        if event in self._subscribers:
            try:
                self._subscribers[event].remove(callback)
            except ValueError:
                pass

    def emit(self, event: str, *args, **kwargs) -> None:
        if event in self._subscribers:
            # Callbacks are called in the order they were subscribed
            for callback in self._subscribers[event]:
                callback(*args, **kwargs)

import os

def parse_config_string(text: str) -> dict:
    config = {}
    current_section = None

    lines = text.splitlines()

    for line_num, line in enumerate(lines, 1):
        line = line.strip()

        # Skip empty lines and comments
        if not line or line.startswith('#') or line.startswith(';'):
            continue

        # Section header
        if line.startswith('[') and line.endswith(']'):
            current_section = line[1:-1].strip()
            if not current_section:
                raise ValueError(f"Empty section name at line {line_num}")
            if current_section not in config:
                config[current_section] = {}
            continue

        # Key-value pair
        if '=' in line:
            if current_section is None:
                raise ValueError(f"Key-value pair found before any section header at line {line_num}")

            key, value = line.split('=', 1)
            key = key.strip()
            value = value.strip()

            # Type coercion
            if value.lower() == 'true':
                coerced_value = True
            elif value.lower() == 'false':
                coerced_value = False
            else:
                try:
                    coerced_value = int(value)
                except ValueError:
                    coerced_value = value

            config[current_section][key] = coerced_value
        else:
            raise ValueError(f"Malformed line at line {line_num}: {line}")

    return config

def parse_config(filepath: str) -> dict:
    with open(filepath, 'r') as f:
        return parse_config_string(f.read())

if __name__ == "__main__":
    # Quick test
    try:
        result = parse_config("workspace/sample.conf")
        print(result)
    except Exception as e:
        print(f"Error: {e}")
